#include <bits/stdc++.h>
using namespace std;
long long q,l,r;
int main()
{
    cin>>q;
    while(q--)
    {
        cin>>l>>r;
        long long t1=l+r,t2=r-l+1;
        if(t1%2==0)
        {
            t1/=2;
        }
        else t2/=2;
        cout<<((t1%9)*(t2%9))%9<<'\n';
    }
    return 0;
}
